import React ,{UseState} from 'react'
import { useState } from 'react';
import {Card,Button,Row,Col} from 'react-bootstrap';


const Pizza = ({pizza}) => {
  const[variant,setVarient]=useState('small');
  const[quantity,setQuantity]=useState(1);


  return (
    <Card style={{ width: '18rem' }}>
      <Card.Img variant="top" src={pizza.image}/>
      <Card.Body>
        <Card.Title>{pizza.name}</Card.Title>
        <Card.Text>
        <Row>
          <Col md={6}>
            <h6>Varient</h6>
            <select>
              {
                pizza.varients.map(varient=>(
                  <option value={varient} onChange={e=>setVarient(e.target.value)}>{varient}</option>
                ))
              }
            </select>
          </Col>
          <Col md={6}>
            <h6>Quantity</h6>
            <select>

            {[...Array(10).keys()].map((v,i)=>(
                <option value={i+1} onChange={(e)=>setQuantity(e.target.value)}>{i+1}</option>
            ))}
            </select>
          </Col>

        </Row>
        </Card.Text>

      </Card.Body>
    </Card>
  )
}

export default Pizza
